"use strict";(self.webpackChunksysanalyst_kb=self.webpackChunksysanalyst_kb||[]).push([["53356"],{15967(i){i.exports=JSON.parse('{"tag":{"label":"fintech","permalink":"/sysanalyst-kb.github.io/docs/tags/fintech","allTagsPath":"/sysanalyst-kb.github.io/docs/tags","count":10,"items":[{"id":"specialization/fintech-analyst-path","title":"FinTech-\u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u2014 \u0440\u043E\u043B\u044C, \u0441\u043F\u0435\u0446\u0438\u0444\u0438\u043A\u0430, \u043A\u0430\u0440\u044C\u0435\u0440\u043D\u044B\u0439 \u043F\u0443\u0442\u044C","description":"FinTech-\u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u2014 \u0441\u0438\u0441\u0442\u0435\u043C\u043D\u044B\u0439 \u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A, \u0441\u043F\u0435\u0446\u0438\u0430\u043B\u0438\u0437\u0438\u0440\u0443\u044E\u0449\u0438\u0439\u0441\u044F \u043D\u0430 \u0444\u0438\u043D\u0430\u043D\u0441\u043E\u0432\u044B\u0445 \u043F\u0440\u043E\u0434\u0443\u043A\u0442\u0430\u0445: \u043F\u043B\u0430\u0442\u0435\u0436\u0430\u0445, \u0431\u0430\u043D\u043A\u0438\u043D\u0433\u0435, \u043A\u0440\u0435\u0434\u0438\u0442\u043E\u0432\u0430\u043D\u0438\u0438. \u0412 \u043E\u0442\u043B\u0438\u0447\u0438\u0435 \u043E\u0442 \xab\u043E\u0431\u044B\u0447\u043D\u043E\u0433\u043E\xbb SA, \u043E\u043D \u0434\u043E\u043B\u0436\u0435\u043D \u043F\u043E\u043D\u0438\u043C\u0430\u0442\u044C \u0440\u0435\u0433\u0443\u043B\u044F\u0442\u043E\u0440\u0438\u043A\u0443 (\u0426\u0411, KYC/AML, PCI DSS), \u043F\u043B\u0430\u0442\u0451\u0436\u043D\u044B\u0435 \u043F\u0440\u043E\u0442\u043E\u043A\u043E\u043B\u044B (ISO 8583, ISO 20022) \u0438 \u0431\u0443\u0445\u0433\u0430\u043B\u0442\u0435\u0440\u0441\u043A\u0438\u0439 \u0443\u0447\u0451\u0442 (double-entry ledger). \u042D\u0442\u043E \u043E\u0434\u043D\u0430 \u0438\u0437 \u0441\u0430\u043C\u044B\u0445 \u0432\u044B\u0441\u043E\u043A\u043E\u043E\u043F\u043B\u0430\u0447\u0438\u0432\u0430\u0435\u043C\u044B\u0445 \u043D\u0438\u0448 \u0434\u043B\u044F \u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A\u0430.","permalink":"/sysanalyst-kb.github.io/docs/specialization/fintech-analyst-path"},{"id":"specialization/fintech-ledger","title":"Ledger \u0438 double-entry \u2014 \u0431\u0443\u0445\u0433\u0430\u043B\u0442\u0435\u0440\u0441\u043A\u0438\u0439 \u0443\u0447\u0451\u0442 \u0434\u043B\u044F \u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A\u0430","description":"Double-entry accounting (\u0434\u0432\u043E\u0439\u043D\u0430\u044F \u0437\u0430\u043F\u0438\u0441\u044C) \u2014 \u043E\u0441\u043D\u043E\u0432\u0430 \u043B\u044E\u0431\u043E\u0439 \u0444\u0438\u043D\u0430\u043D\u0441\u043E\u0432\u043E\u0439 \u0441\u0438\u0441\u0442\u0435\u043C\u044B. \u041A\u0430\u0436\u0434\u0430\u044F \u0442\u0440\u0430\u043D\u0437\u0430\u043A\u0446\u0438\u044F \u0437\u0430\u043F\u0438\u0441\u044B\u0432\u0430\u0435\u0442\u0441\u044F \u0434\u0432\u0430\u0436\u0434\u044B: \u0434\u0435\u0431\u0435\u0442 \u043E\u0434\u043D\u043E\u0433\u043E \u0441\u0447\u0451\u0442\u0430 \u0438 \u043A\u0440\u0435\u0434\u0438\u0442 \u0434\u0440\u0443\u0433\u043E\u0433\u043E. \u0421\u0443\u043C\u043C\u0430 \u0434\u0435\u0431\u0435\u0442\u043E\u0432 \u0432\u0441\u0435\u0433\u0434\u0430 \u0440\u0430\u0432\u043D\u0430 \u0441\u0443\u043C\u043C\u0435 \u043A\u0440\u0435\u0434\u0438\u0442\u043E\u0432. \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u0434\u043E\u043B\u0436\u0435\u043D \u043F\u043E\u043D\u0438\u043C\u0430\u0442\u044C, \u043A\u0430\u043A \u0441\u043F\u0440\u043E\u0435\u043A\u0442\u0438\u0440\u043E\u0432\u0430\u0442\u044C ledger, \u0447\u0442\u043E \u0442\u0430\u043A\u043E\u0435 \u043F\u043B\u0430\u043D \u0441\u0447\u0435\u0442\u043E\u0432, \u043A\u0430\u043A \u0444\u043E\u0440\u043C\u0438\u0440\u0443\u044E\u0442\u0441\u044F \u043F\u0440\u043E\u0432\u043E\u0434\u043A\u0438 \u0438 \u043F\u043E\u0447\u0435\u043C\u0443 \u0441\u0438\u0441\u0442\u0435\u043C\u0430 \xab\u043D\u0435 \u0441\u0445\u043E\u0434\u0438\u0442\u0441\u044F\xbb.","permalink":"/sysanalyst-kb.github.io/docs/specialization/fintech-ledger"},{"id":"specialization/fintech-open-banking","title":"Open Banking / PSD2 \u2014 API, SCA, Berlin Group","description":"Open Banking \u2014 \u0442\u0440\u0435\u0431\u043E\u0432\u0430\u043D\u0438\u0435 \u0440\u0435\u0433\u0443\u043B\u044F\u0442\u043E\u0440\u0430 (PSD2 \u0432 EU, Open Banking Standard \u0432 UK) \u0437\u0430\u0441\u0442\u0430\u0432\u0438\u0442\u044C \u0431\u0430\u043D\u043A\u0438 \u043E\u0442\u043A\u0440\u044B\u0442\u044C API \u0434\u043B\u044F \u0442\u0440\u0435\u0442\u044C\u0438\u0445 \u0441\u0442\u043E\u0440\u043E\u043D. \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u0434\u043E\u043B\u0436\u0435\u043D \u043F\u043E\u043D\u0438\u043C\u0430\u0442\u044C: \u043A\u0430\u043A\u0438\u0435 \u0442\u0438\u043F\u044B API \u043D\u0443\u0436\u043D\u044B (AISP, PISP), \u043A\u0430\u043A \u0440\u0430\u0431\u043E\u0442\u0430\u0435\u0442 consent management, \u0447\u0442\u043E \u0442\u0430\u043A\u043E\u0435 SCA (\u0441\u0438\u043B\u044C\u043D\u0430\u044F \u0430\u0443\u0442\u0435\u043D\u0442\u0438\u0444\u0438\u043A\u0430\u0446\u0438\u044F), \u0438 \u043A\u0430\u043A\u0438\u0435 \u0441\u0442\u0430\u043D\u0434\u0430\u0440\u0442\u044B \u043E\u043F\u0438\u0441\u044B\u0432\u0430\u044E\u0442 API (Berlin Group, UK Standard, FAPI).","permalink":"/sysanalyst-kb.github.io/docs/specialization/fintech-open-banking"},{"id":"specialization/fintech-lending","title":"\u041A\u0440\u0435\u0434\u0438\u0442\u043D\u044B\u0439 \u043A\u043E\u043D\u0432\u0435\u0439\u0435\u0440 \u2014 loan origination, scoring, amortization","description":"\u041A\u0440\u0435\u0434\u0438\u0442\u043D\u044B\u0439 \u043A\u043E\u043D\u0432\u0435\u0439\u0435\u0440 (loan origination system) \u2014 \u043F\u0440\u043E\u0446\u0435\u0441\u0441 \u043E\u0442 \u043F\u043E\u0434\u0430\u0447\u0438 \u0437\u0430\u044F\u0432\u043A\u0438 \u0434\u043E \u0432\u044B\u0434\u0430\u0447\u0438 \u043A\u0440\u0435\u0434\u0438\u0442\u0430 \u0438 \u0435\u0433\u043E \u043F\u043E\u0433\u0430\u0448\u0435\u043D\u0438\u044F. \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u0434\u043E\u043B\u0436\u0435\u043D \u043F\u043E\u043D\u0438\u043C\u0430\u0442\u044C \u044D\u0442\u0430\u043F\u044B: \u0437\u0430\u044F\u0432\u043A\u0430 \u2192 \u0441\u043A\u043E\u0440\u0438\u043D\u0433 \u2192 \u0440\u0435\u0448\u0435\u043D\u0438\u0435 \u2192 \u0432\u044B\u0434\u0430\u0447\u0430 \u2192 \u043E\u0431\u0441\u043B\u0443\u0436\u0438\u0432\u0430\u043D\u0438\u0435 \u2192 \u043F\u043E\u0433\u0430\u0448\u0435\u043D\u0438\u0435. \u0421\u043A\u043E\u0440\u0438\u043D\u0433 \u2014 ML-\u043C\u043E\u0434\u0435\u043B\u044C, \u043E\u0446\u0435\u043D\u0438\u0432\u0430\u044E\u0449\u0430\u044F \u0432\u0435\u0440\u043E\u044F\u0442\u043D\u043E\u0441\u0442\u044C \u0434\u0435\u0444\u043E\u043B\u0442\u0430. \u0410\u043C\u043E\u0440\u0442\u0438\u0437\u0430\u0446\u0438\u044F \u2014 \u0433\u0440\u0430\u0444\u0438\u043A \u043F\u043B\u0430\u0442\u0435\u0436\u0435\u0439 (\u0430\u043D\u043D\u0443\u0438\u0442\u0435\u0442\u043D\u044B\u0439 / \u0434\u0438\u0444\u0444\u0435\u0440\u0435\u043D\u0446\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u044B\u0439). BNPL \u2014 \u043E\u0442\u0434\u0435\u043B\u044C\u043D\u044B\u0439 \u043F\u0440\u043E\u0434\u0443\u043A\u0442.","permalink":"/sysanalyst-kb.github.io/docs/specialization/fintech-lending"},{"id":"specialization/industry-analytics","title":"\u041E\u0442\u0440\u0430\u0441\u043B\u0435\u0432\u0430\u044F \u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A\u0430 (FinTech, Retail, Logistics)","description":"\u0421\u0438\u0441\u0442\u0435\u043C\u043D\u044B\u0439 \u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u043E\u0431\u044B\u0447\u043D\u043E \u0440\u0430\u0431\u043E\u0442\u0430\u0435\u0442 \u043D\u0435 \u0432 \u0432\u0430\u043A\u0443\u0443\u043C\u0435, \u0430 \u0432 \u043A\u043E\u043D\u043A\u0440\u0435\u0442\u043D\u043E\u0439 \u043E\u0442\u0440\u0430\u0441\u043B\u0438. \u0420\u0430\u0437\u043D\u044B\u0435 \u043E\u0442\u0440\u0430\u0441\u043B\u0438 \u0438\u043C\u0435\u044E\u0442 \u0440\u0430\u0437\u043D\u0443\u044E \u0441\u043F\u0435\u0446\u0438\u0444\u0438\u043A\u0443: \u0442\u0435\u0440\u043C\u0438\u043D\u043E\u043B\u043E\u0433\u0438\u044E, \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u044B, \u0442\u0440\u0435\u0431\u043E\u0432\u0430\u043D\u0438\u044F \u043A \u0441\u0438\u0441\u0442\u0435\u043C\u0435, \u0440\u0435\u0433\u0443\u043B\u044F\u0446\u0438\u044E.","permalink":"/sysanalyst-kb.github.io/docs/specialization/industry-analytics"},{"id":"specialization/fintech-protocols","title":"\u041F\u043B\u0430\u0442\u0451\u0436\u043D\u044B\u0435 \u043F\u0440\u043E\u0442\u043E\u043A\u043E\u043B\u044B \u2014 ISO 8583, ISO 20022, SWIFT, SEPA","description":"\u041F\u043B\u0430\u0442\u0451\u0436\u043D\u044B\u0435 \u043F\u0440\u043E\u0442\u043E\u043A\u043E\u043B\u044B \u2014 \u0444\u043E\u0440\u043C\u0430\u0442\u044B \u0441\u043E\u043E\u0431\u0449\u0435\u043D\u0438\u0439, \u043A\u043E\u0442\u043E\u0440\u044B\u043C\u0438 \u043E\u0431\u043C\u0435\u043D\u0438\u0432\u0430\u044E\u0442\u0441\u044F \u0443\u0447\u0430\u0441\u0442\u043D\u0438\u043A\u0438 \u043F\u043B\u0430\u0442\u0451\u0436\u043D\u043E\u0433\u043E \u0440\u044B\u043D\u043A\u0430. \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u0434\u043E\u043B\u0436\u0435\u043D \u0443\u043C\u0435\u0442\u044C \u0447\u0438\u0442\u0430\u0442\u044C \u0441\u043F\u0435\u0446\u0438\u0444\u0438\u043A\u0430\u0446\u0438\u044E \u043F\u0440\u043E\u0442\u043E\u043A\u043E\u043B\u0430, \u043F\u043E\u043D\u0438\u043C\u0430\u0442\u044C \u043E\u0431\u044F\u0437\u0430\u0442\u0435\u043B\u044C\u043D\u044B\u0435 \u0438 \u043E\u043F\u0446\u0438\u043E\u043D\u0430\u043B\u044C\u043D\u044B\u0435 \u043F\u043E\u043B\u044F, \u0437\u043D\u0430\u0442\u044C, \u043A\u0430\u043A \u0442\u0440\u0430\u043D\u0437\u0430\u043A\u0446\u0438\u044F \xab\u0443\u043F\u0430\u043A\u043E\u0432\u044B\u0432\u0430\u0435\u0442\u0441\u044F\xbb \u0432 \u0441\u043E\u043E\u0431\u0449\u0435\u043D\u0438\u0435. \u041E\u0441\u043D\u043E\u0432\u043D\u044B\u0435: ISO 8583 (\u043A\u0430\u0440\u0442\u043E\u0447\u043D\u044B\u0435 \u0442\u0440\u0430\u043D\u0437\u0430\u043A\u0446\u0438\u0438), ISO 20022 (\u043D\u043E\u0432\u044B\u0439 \u0441\u0442\u0430\u043D\u0434\u0430\u0440\u0442 \u043F\u043B\u0430\u0442\u0435\u0436\u0435\u0439), SWIFT MT/MX (\u043C\u0435\u0436\u0431\u0430\u043D\u043A\u043E\u0432\u0441\u043A\u0438\u0435 \u0441\u043E\u043E\u0431\u0449\u0435\u043D\u0438\u044F), SEPA (\u0435\u0432\u0440\u043E\u043F\u0435\u0439\u0441\u043A\u0438\u0435 \u043F\u043B\u0430\u0442\u0451\u0436\u043D\u044B\u0435 \u0441\u0445\u0435\u043C\u044B).","permalink":"/sysanalyst-kb.github.io/docs/specialization/fintech-protocols"},{"id":"specialization/fintech-payments","title":"\u041F\u043B\u0430\u0442\u0451\u0436\u043D\u044B\u0435 \u0441\u0438\u0441\u0442\u0435\u043C\u044B \u2014 4-\u0441\u0442\u043E\u0440\u043E\u043D\u043D\u044F\u044F \u043C\u043E\u0434\u0435\u043B\u044C, acquiring, issuing","description":"\u041F\u043B\u0430\u0442\u0451\u0436\u043D\u0430\u044F \u0441\u0438\u0441\u0442\u0435\u043C\u0430 \u2014 \u044D\u0442\u043E \u043C\u0435\u0445\u0430\u043D\u0438\u0437\u043C \u043F\u0435\u0440\u0435\u0432\u043E\u0434\u0430 \u0434\u0435\u043D\u0435\u0433 \u043E\u0442 \u043F\u043B\u0430\u0442\u0435\u043B\u044C\u0449\u0438\u043A\u0430 \u043A \u043F\u043E\u043B\u0443\u0447\u0430\u0442\u0435\u043B\u044E. \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A\u0443 \u043D\u0443\u0436\u043D\u043E \u043F\u043E\u043D\u0438\u043C\u0430\u0442\u044C 4-\u0441\u0442\u043E\u0440\u043E\u043D\u043D\u044E\u044E \u043C\u043E\u0434\u0435\u043B\u044C (\u0434\u0435\u0440\u0436\u0430\u0442\u0435\u043B\u044C \u043A\u0430\u0440\u0442\u044B \u2192 \u0431\u0430\u043D\u043A-\u044D\u043C\u0438\u0442\u0435\u043D\u0442 \u2192 \u043F\u043B\u0430\u0442\u0451\u0436\u043D\u0430\u044F \u0441\u0438\u0441\u0442\u0435\u043C\u0430 \u2192 \u0431\u0430\u043D\u043A-\u044D\u043A\u0432\u0430\u0439\u0440\u0435\u0440 \u2192 \u043C\u0435\u0440\u0447\u0430\u043D\u0442), \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u044B\u0439 \u0446\u0438\u043A\u043B \u0442\u0440\u0430\u043D\u0437\u0430\u043A\u0446\u0438\u0438 (\u0430\u0432\u0442\u043E\u0440\u0438\u0437\u0430\u0446\u0438\u044F \u2192 \u043A\u043B\u0438\u0440\u0438\u043D\u0433 \u2192 settlement) \u0438 \u043A\u0430\u043A \u044D\u0442\u043E \u0432\u043B\u0438\u044F\u0435\u0442 \u043D\u0430 \u0442\u0440\u0435\u0431\u043E\u0432\u0430\u043D\u0438\u044F \u043A \u0441\u0438\u0441\u0442\u0435\u043C\u0435.","permalink":"/sysanalyst-kb.github.io/docs/specialization/fintech-payments"},{"id":"specialization/fintech-regulation","title":"\u0420\u0435\u0433\u0443\u043B\u044F\u0442\u043E\u0440\u0438\u043A\u0430 \u0432 FinTech \u2014 KYC/AML, PCI DSS, \u0426\u0411, PSD2","description":"FinTech \u2014 \u0441\u0430\u043C\u0430\u044F \u0440\u0435\u0433\u0443\u043B\u0438\u0440\u0443\u0435\u043C\u0430\u044F \u043E\u0442\u0440\u0430\u0441\u043B\u044C IT. \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u0434\u043E\u043B\u0436\u0435\u043D \u0437\u043D\u0430\u0442\u044C \u043A\u043B\u044E\u0447\u0435\u0432\u044B\u0435 \u0440\u0435\u0433\u0443\u043B\u044F\u0442\u043E\u0440\u043D\u044B\u0435 \u0442\u0440\u0435\u0431\u043E\u0432\u0430\u043D\u0438\u044F \u0438 \u0442\u043E, \u043A\u0430\u043A \u043E\u043D\u0438 \u0432\u043B\u0438\u044F\u044E\u0442 \u043D\u0430 \u0430\u0440\u0445\u0438\u0442\u0435\u043A\u0442\u0443\u0440\u0443 \u0441\u0438\u0441\u0442\u0435\u043C\u044B. \u041E\u0441\u043D\u043E\u0432\u043D\u044B\u0435 traceability matrix, audit trails, \u043C\u0430\u0441\u043A\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u0435 \u0434\u0430\u043D\u043D\u044B\u0445, encryption.","permalink":"/sysanalyst-kb.github.io/docs/specialization/fintech-regulation"},{"id":"specialization/fintech-reconciliation","title":"\u0421\u0432\u0435\u0440\u043A\u0430 \u0434\u0430\u043D\u043D\u044B\u0445 (Reconciliation) \u0432 FinTech","description":"Reconciliation (\u0441\u0432\u0435\u0440\u043A\u0430) \u2014 \u043F\u0440\u043E\u0446\u0435\u0441\u0441 \u0441\u0440\u0430\u0432\u043D\u0435\u043D\u0438\u044F \u0434\u0432\u0443\u0445 \u043D\u0430\u0431\u043E\u0440\u043E\u0432 \u0434\u0430\u043D\u043D\u044B\u0445, \u0447\u0442\u043E\u0431\u044B \u0443\u0431\u0435\u0434\u0438\u0442\u044C\u0441\u044F, \u0447\u0442\u043E \u043E\u043D\u0438 \u0441\u043E\u0432\u043F\u0430\u0434\u0430\u044E\u0442. \u0412 FinTech \u043F\u0440\u0430\u0432\u0438\u043B\u0430 matching, \u043E\u0431\u0440\u0430\u0431\u043E\u0442\u043A\u0443 break\'\u043E\u0432, \u043F\u0435\u0440\u0438\u043E\u0434\u0438\u0447\u043D\u043E\u0441\u0442\u044C, SLA \u0442\u043E\u0447\u043D\u043E\u0441\u0442\u0438.","permalink":"/sysanalyst-kb.github.io/docs/specialization/fintech-reconciliation"},{"id":"specialization/fintech-fraud","title":"\u0424\u0440\u043E\u0434-\u043C\u043E\u043D\u0438\u0442\u043E\u0440\u0438\u043D\u0433 \u0432 FinTech \u2014 \u0430\u043D\u0442\u0438\u0444\u0440\u043E\u0434-\u0441\u0438\u0441\u0442\u0435\u043C\u044B","description":"\u0424\u0440\u043E\u0434-\u043C\u043E\u043D\u0438\u0442\u043E\u0440\u0438\u043D\u0433 (\u0430\u043D\u0442\u0438\u0444\u0440\u043E\u0434) \u2014 \u0441\u0438\u0441\u0442\u0435\u043C\u0430 \u0432\u044B\u044F\u0432\u043B\u0435\u043D\u0438\u044F \u043F\u043E\u0434\u043E\u0437\u0440\u0438\u0442\u0435\u043B\u044C\u043D\u044B\u0445 \u043E\u043F\u0435\u0440\u0430\u0446\u0438\u0439 \u0432 \u0440\u0435\u0430\u043B\u044C\u043D\u043E\u043C \u0432\u0440\u0435\u043C\u0435\u043D\u0438. \u041A\u0430\u0436\u0434\u0430\u044F \u0442\u0440\u0430\u043D\u0437\u0430\u043A\u0446\u0438\u044F \u043F\u0440\u043E\u0432\u0435\u0440\u044F\u0435\u0442\u0441\u044F \u043F\u043E \u043F\u0440\u0430\u0432\u0438\u043B\u0430\u043C \u0438 ML-\u043C\u043E\u0434\u0435\u043B\u044F\u043C \u0434\u043E \u0442\u043E\u0433\u043E, \u043A\u0430\u043A \u0431\u0443\u0434\u0435\u0442 \u043E\u0434\u043E\u0431\u0440\u0435\u043D\u0430. \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u0441\u043F\u0435\u0446\u0438\u0444\u0438\u0446\u0438\u0440\u0443\u0435\u0442: \u043F\u0440\u0430\u0432\u0438\u043B\u0430 \u0444\u0440\u043E\u0434-\u0441\u043A\u043E\u0440\u0438\u043D\u0433\u0430, \u0438\u043D\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u044E \u0441 \u0432\u043D\u0435\u0448\u043D\u0438\u043C\u0438 \u0447\u0451\u0440\u043D\u044B\u043C\u0438 \u0441\u043F\u0438\u0441\u043A\u0430\u043C\u0438, \u043C\u0435\u0445\u0430\u043D\u0438\u0437\u043C \u0431\u043B\u043E\u043A\u0438\u0440\u043E\u0432\u043A\u0438, case management \u0434\u043B\u044F \u0440\u0443\u0447\u043D\u043E\u0433\u043E \u0440\u0430\u0437\u0431\u043E\u0440\u0430.","permalink":"/sysanalyst-kb.github.io/docs/specialization/fintech-fraud"}],"unlisted":false}}')}}]);